import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Encode user input to prevent XSS
        String safeUserInput = encodeForHTML(userInput);

        String output = "<html><body>Welcome, " + safeUserInput + "</body></html>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    // Method to safely encode user input for HTML content
    private String encodeForHTML(String input) {
        return org.owasp.esapi.codecs.HTMLEntityCodec.getInstance().encodeForHTML(input);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
